namespace ContosoUniversity.Tests;

[TestClass]
public class PaginatedListTests
{
    // Constructor tests

    [TestMethod]
    public void Constructor_SetsPageIndex_Correctly()
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int> { 1, 2 }, count: 10, pageIndex: 3, pageSize: 2);

        // Assert
        Assert.AreEqual(3, list.PageIndex);
    }

    [TestMethod]
    public void Constructor_ExactDivision_CalculatesTotalPagesCorrectly()
    {
        // 10 items / 5 per page = 2 pages
        var list = new PaginatedList<int>(new List<int> { 1 }, count: 10, pageIndex: 1, pageSize: 5);
        Assert.AreEqual(2, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_WithRemainder_RoundsUpTotalPages()
    {
        // 11 items / 5 per page = 3 pages
        var list = new PaginatedList<int>(new List<int> { 1 }, count: 11, pageIndex: 1, pageSize: 5);
        Assert.AreEqual(3, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_SinglePage_TotalPagesIsOne()
    {
        var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, count: 3, pageIndex: 1, pageSize: 10);
        Assert.AreEqual(1, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_ManyPages_CalculatesTotalPagesCorrectly()
    {
        // 100 items / 3 per page = 34 pages
        var list = new PaginatedList<int>(new List<int> { 1 }, count: 100, pageIndex: 1, pageSize: 3);
        Assert.AreEqual(34, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_AddsItemsToList()
    {
        var items = new List<int> { 10, 20, 30 };
        var list = new PaginatedList<int>(items, count: 10, pageIndex: 1, pageSize: 3);

        Assert.AreEqual(3, list.Count);
        Assert.AreEqual(10, list[0]);
        Assert.AreEqual(20, list[1]);
        Assert.AreEqual(30, list[2]);
    }

    // HasPreviousPage tests

    [TestMethod]
    [DataRow(1, false, DisplayName = "Page 1 has no previous page")]
    [DataRow(2, true, DisplayName = "Page 2 has previous page")]
    [DataRow(5, true, DisplayName = "Page 5 has previous page")]
    public void HasPreviousPage_VariousPages_ReturnsExpected(int pageIndex, bool expected)
    {
        var list = new PaginatedList<int>(new List<int> { 1 }, count: 50, pageIndex: pageIndex, pageSize: 10);
        Assert.AreEqual(expected, list.HasPreviousPage);
    }

    // HasNextPage tests

    [TestMethod]
    [DataRow(1, 5, true, DisplayName = "Page 1 of 5 has next page")]
    [DataRow(4, 5, true, DisplayName = "Page 4 of 5 has next page")]
    [DataRow(5, 5, false, DisplayName = "Page 5 of 5 has no next page")]
    [DataRow(1, 1, false, DisplayName = "Page 1 of 1 has no next page")]
    public void HasNextPage_VariousPages_ReturnsExpected(int pageIndex, int totalPages, bool expected)
    {
        // count = totalPages * pageSize to get exact totalPages
        int pageSize = 10;
        int count = totalPages * pageSize;
        var list = new PaginatedList<int>(new List<int> { 1 }, count: count, pageIndex: pageIndex, pageSize: pageSize);

        Assert.AreEqual(expected, list.HasNextPage);
    }

    // Create method tests

    [TestMethod]
    public void Create_Page1_ReturnsFirstPageItems()
    {
        var source = Enumerable.Range(1, 20).ToList().AsQueryable();

        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 5);

        Assert.AreEqual(5, result.Count);
        CollectionAssert.AreEqual(new List<int> { 1, 2, 3, 4, 5 }, result.ToList());
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages);
    }

    [TestMethod]
    public void Create_MiddlePage_ReturnsCorrectItems()
    {
        var source = Enumerable.Range(1, 20).ToList().AsQueryable();

        var result = PaginatedList<int>.Create(source, pageIndex: 2, pageSize: 5);

        CollectionAssert.AreEqual(new List<int> { 6, 7, 8, 9, 10 }, result.ToList());
        Assert.AreEqual(2, result.PageIndex);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        var source = Enumerable.Range(1, 13).ToList().AsQueryable();

        var result = PaginatedList<int>.Create(source, pageIndex: 3, pageSize: 5);

        CollectionAssert.AreEqual(new List<int> { 11, 12, 13 }, result.ToList());
        Assert.AreEqual(3, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var source = new List<int>().AsQueryable();

        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 5);

        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
        Assert.AreEqual(1, result.PageIndex);
    }

    [TestMethod]
    public void Create_PageSizeOfOne_ReturnsOneItemPerPage()
    {
        var source = Enumerable.Range(1, 5).ToList().AsQueryable();

        var result = PaginatedList<int>.Create(source, pageIndex: 3, pageSize: 1);

        Assert.AreEqual(1, result.Count);
        Assert.AreEqual(3, result[0]);
        Assert.AreEqual(5, result.TotalPages);
        Assert.IsTrue(result.HasPreviousPage);
        Assert.IsTrue(result.HasNextPage);
    }

    [TestMethod]
    public void Create_SingleItemTotal_ReturnsSinglePage()
    {
        var source = new List<int> { 42 }.AsQueryable();

        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        Assert.AreEqual(1, result.Count);
        Assert.AreEqual(42, result[0]);
        Assert.AreEqual(1, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }
}

