using Microsoft.AspNetCore.Mvc.Rendering;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public class DepartmentsControllerTests
    {
        private SchoolContext _context = null!;
        private DepartmentsController _controller = null!;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new DepartmentsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private void SeedDepartmentsWithInstructors()
        {
            TestHelpers.SeedInstructors(_context);

            _context.Departments.AddRange(
                new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 10 },
                new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 11 },
                new Department { DepartmentID = 3, Name = "Engineering", Budget = 350000, StartDate = DateTime.Parse("2007-09-01") }
            );
            _context.SaveChanges();
        }

        // ===================== Index =====================

        [TestMethod]
        public void Index_ReturnsViewResult_WithListOfDepartments()
        {
            SeedDepartmentsWithInstructors();

            var result = _controller.Index();

            var viewResult = result as ViewResult;
            Assert.IsNotNull(viewResult);
            var model = viewResult.Model as List<Department>;
            Assert.IsNotNull(model);
            Assert.AreEqual(3, model.Count);
        }

        // ===================== Details =====================

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = result as StatusCodeResult;
            Assert.IsNotNull(statusResult);
            Assert.AreEqual(400, statusResult.StatusCode);
        }

        [TestMethod]
        public void Details_NonexistentId_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsInstanceOfType<NotFoundResult>(result);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            SeedDepartmentsWithInstructors();

            var result = _controller.Details(1);

            var viewResult = result as ViewResult;
            Assert.IsNotNull(viewResult);
            var model = viewResult.Model as Department;
            Assert.IsNotNull(model);
            Assert.AreEqual("English", model.Name);
        }

        // ===================== Create GET =====================

        [TestMethod]
        public void Create_GET_ReturnsViewWithInstructorSelectList()
        {
            TestHelpers.SeedInstructors(_context);

            var result = _controller.Create();

            var viewResult = result as ViewResult;
            Assert.IsNotNull(viewResult);
            Assert.IsNotNull(_controller.ViewBag.InstructorID);
            var selectList = _controller.ViewBag.InstructorID as SelectList;
            Assert.IsNotNull(selectList);
        }

        // ===================== Create POST =====================

        [TestMethod]
        public void Create_POST_ValidDepartment_SavesAndRedirectsToIndex()
        {
            TestHelpers.SeedInstructors(_context);
            var department = new Department
            {
                Name = "Physics",
                Budget = 200000,
                StartDate = DateTime.Parse("2010-01-01"),
                InstructorID = 10
            };

            var result = _controller.Create(department);

            var redirect = result as RedirectToActionResult;
            Assert.IsNotNull(redirect);
            Assert.AreEqual("Index", redirect.ActionName);
            Assert.AreEqual(1, _context.Departments.Count());
            Assert.AreEqual("Physics", _context.Departments.First().Name);
        }

        [TestMethod]
        public void Create_POST_InvalidModel_ReturnsViewWithDepartmentAndSelectList()
        {
            TestHelpers.SeedInstructors(_context);
            var department = new Department
            {
                Name = "Physics",
                Budget = 200000,
                StartDate = DateTime.Parse("2010-01-01"),
                InstructorID = 10
            };
            _controller.ModelState.AddModelError("Name", "Required");

            var result = _controller.Create(department);

            var viewResult = result as ViewResult;
            Assert.IsNotNull(viewResult);
            var model = viewResult.Model as Department;
            Assert.IsNotNull(model);
            Assert.AreEqual("Physics", model.Name);
            Assert.IsNotNull(_controller.ViewBag.InstructorID);
            var selectList = _controller.ViewBag.InstructorID as SelectList;
            Assert.IsNotNull(selectList);
        }

        // ===================== Edit GET =====================

        [TestMethod]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null as int?);

            var statusResult = result as StatusCodeResult;
            Assert.IsNotNull(statusResult);
            Assert.AreEqual(400, statusResult.StatusCode);
        }

        [TestMethod]
        public void Edit_GET_NonexistentId_ReturnsNotFound()
        {
            var result = _controller.Edit(999 as int?);

            Assert.IsInstanceOfType<NotFoundResult>(result);
        }

        [TestMethod]
        public void Edit_GET_ValidId_ReturnsViewWithDepartment()
        {
            SeedDepartmentsWithInstructors();

            var result = _controller.Edit(1 as int?);

            var viewResult = result as ViewResult;
            Assert.IsNotNull(viewResult);
            var model = viewResult.Model as Department;
            Assert.IsNotNull(model);
            Assert.AreEqual("English", model.Name);
            Assert.IsNotNull(_controller.ViewBag.InstructorID);
        }

        // ===================== Edit POST =====================

        [TestMethod]
        public void Edit_POST_ValidDepartment_SavesAndRedirectsToIndex()
        {
            SeedDepartmentsWithInstructors();
            var department = _context.Departments.Find(1)!;
            // Detach so we can attach the modified version
            _context.Entry(department).State = EntityState.Detached;

            department.Name = "Updated English";

            var result = _controller.Edit(department);

            var redirect = result as RedirectToActionResult;
            Assert.IsNotNull(redirect);
            Assert.AreEqual("Index", redirect.ActionName);
        }

        [TestMethod]
        public void Edit_POST_InvalidModel_ReturnsViewWithDepartment()
        {
            SeedDepartmentsWithInstructors();
            var department = new Department
            {
                DepartmentID = 1,
                Name = "English",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 10
            };
            _controller.ModelState.AddModelError("Name", "Required");

            var result = _controller.Edit(department);

            var viewResult = result as ViewResult;
            Assert.IsNotNull(viewResult);
            var model = viewResult.Model as Department;
            Assert.IsNotNull(model);
            Assert.IsNotNull(_controller.ViewBag.InstructorID);
        }

        // ===================== Delete GET =====================

        [TestMethod]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = result as StatusCodeResult;
            Assert.IsNotNull(statusResult);
            Assert.AreEqual(400, statusResult.StatusCode);
        }

        [TestMethod]
        public void Delete_GET_NonexistentId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsInstanceOfType<NotFoundResult>(result);
        }

        [TestMethod]
        public void Delete_GET_ValidId_ReturnsViewWithDepartment()
        {
            SeedDepartmentsWithInstructors();

            var result = _controller.Delete(1);

            var viewResult = result as ViewResult;
            Assert.IsNotNull(viewResult);
            var model = viewResult.Model as Department;
            Assert.IsNotNull(model);
            Assert.AreEqual("English", model.Name);
        }

        // ===================== DeleteConfirmed POST =====================

        [TestMethod]
        public void DeleteConfirmed_RemovesDepartmentAndRedirectsToIndex()
        {
            SeedDepartmentsWithInstructors();

            var result = _controller.DeleteConfirmed(1);

            var redirect = result as RedirectToActionResult;
            Assert.IsNotNull(redirect);
            Assert.AreEqual("Index", redirect.ActionName);
            Assert.AreEqual(2, _context.Departments.Count());
            Assert.IsNull(_context.Departments.Find(1));
        }
    }
}

