using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public class HomeControllerTests
    {
        private SchoolContext _context = null!;
        private HomeController _controller = null!;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new HomeController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }

        [TestMethod]
        public void About_ReturnsViewResult_WithEnrollmentDateGroupList()
        {
            var result = _controller.About();

            var viewResult = result as ViewResult;
            Assert.IsNotNull(viewResult);
            Assert.IsInstanceOfType(viewResult.Model, typeof(List<EnrollmentDateGroup>));
        }

        [TestMethod]
        public void About_EmptyDatabase_ReturnsEmptyList()
        {
            var result = _controller.About() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            Assert.AreEqual(0, model.Count);
        }

        [TestMethod]
        public void About_WithSeededStudents_ReturnsCorrectGroupingAndCounts()
        {
            // Seed students: 1 on 2020-09-01, 1 on 2021-09-01, 1 on 2022-09-01
