            var result = _controller.About() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            Assert.AreEqual(3, model.Count);
            Assert.IsTrue(model.All(g => g.StudentCount == 1));
        }

        [TestMethod]
        public void About_WithMultipleStudentsSameDate_ReturnsCorrectCount()
        {
            var date = DateTime.Parse("2020-09-01");
            _context.Students.AddRange(
                new Student { FirstMidName = "A", LastName = "A", EnrollmentDate = date },
                new Student { FirstMidName = "B", LastName = "B", EnrollmentDate = date },
                new Student { FirstMidName = "C", LastName = "C", EnrollmentDate = date }
            );
            _context.SaveChanges();

            var result = _controller.About() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual(3, model[0].StudentCount);
            Assert.AreEqual(date, model[0].EnrollmentDate);
        }

