namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public class NotificationsControllerTests
    {
        private SchoolContext _context = null!;
        private NotificationsController _controller = null!;
        private NotificationService _notificationService = null!;

        [TestInitialize]
        public void Setup()
        {
            // Drain the static queue before each test
            var drainer = new NotificationService();
            while (drainer.ReceiveNotification() != null) { }
            drainer.Dispose();

            _context = TestHelpers.CreateInMemoryContext();
            _controller = new NotificationsController(_context);
            _notificationService = new NotificationService();
        }

        [TestCleanup]
        public void Cleanup()
        {
            // Drain again to leave clean state
            while (_notificationService.ReceiveNotification() != null) { }
            _notificationService.Dispose();
            _controller.Dispose();
            _context.Dispose();
        }

        [TestMethod]
        public void GetNotifications_NoNotifications_ReturnsSuccessWithZeroCount()
        {
            var result = _controller.GetNotifications();

            Assert.IsNotNull(result);
            var jsonResult = result as JsonResult;
            Assert.IsNotNull(jsonResult);
            dynamic value = jsonResult.Value!;
            var type = value.GetType();
            Assert.AreEqual(true, (bool)type.GetProperty("success")!.GetValue(value));
            Assert.AreEqual(0, (int)type.GetProperty("count")!.GetValue(value));
        }

        [TestMethod]
        public void GetNotifications_AfterSendingNotifications_ReturnsThem()
        {
            _notificationService.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");
            _notificationService.SendNotification("Course", "2", EntityOperation.UPDATE, "TestUser");

            var result = _controller.GetNotifications() as JsonResult;
            Assert.IsNotNull(result);
            var type = result.Value!.GetType();
            Assert.AreEqual(true, (bool)type.GetProperty("success")!.GetValue(result.Value));
            Assert.AreEqual(2, (int)type.GetProperty("count")!.GetValue(result.Value));
        }

        [TestMethod]
        public void GetNotifications_ReturnsMax10Notifications()
        {
            // Send 15 notifications
            for (int i = 0; i < 15; i++)
            {
                _notificationService.SendNotification("Entity", i.ToString(), EntityOperation.CREATE, "TestUser");
            }

            var result = _controller.GetNotifications() as JsonResult;
            Assert.IsNotNull(result);
            var type = result.Value!.GetType();
            Assert.AreEqual(true, (bool)type.GetProperty("success")!.GetValue(result.Value));
            Assert.AreEqual(10, (int)type.GetProperty("count")!.GetValue(result.Value));
        }

        [TestMethod]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(1) as JsonResult;

            Assert.IsNotNull(result);
            var type = result.Value!.GetType();
            Assert.AreEqual(true, (bool)type.GetProperty("success")!.GetValue(result.Value));
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }
    }
}

