        public void Details_NonexistentId_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsInstanceOfType(result, typeof(NotFoundResult));
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewResultWithInstructor()
        {
            TestHelpers.SeedInstructors(_context);

            var result = _controller.Details(10) as ViewResult;

            Assert.IsNotNull(result);
            var instructor = result.Model as Instructor;
            Assert.IsNotNull(instructor);
            Assert.AreEqual(10, instructor.ID);
            Assert.AreEqual("Abercrombie", instructor.LastName);
        }

        [TestMethod]
        public void Create_GET_ReturnsViewResultWithInstructor()
        {
            // Need courses in DB for PopulateAssignedCourseData
            TestHelpers.SeedCourses(_context);

            var result = _controller.Create() as ViewResult;

            Assert.IsNotNull(result);
            var instructor = result.Model as Instructor;
            Assert.IsNotNull(instructor);
            Assert.IsNotNull(instructor.CourseAssignments);
            Assert.AreEqual(0, instructor.CourseAssignments.Count);
        }

        [TestMethod]
        public void Create_POST_ValidInstructor_SavesAndRedirects()
        {
            var instructor = new Instructor
            {
                FirstMidName = "John",
                LastName = "Doe",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null);

            Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
            var redirect = (RedirectToActionResult)result;
            Assert.AreEqual("Index", redirect.ActionName);
            Assert.AreEqual(1, _context.Instructors.Count());
        }

        [TestMethod]
        public void Create_POST_WithSelectedCourses_AddsCourseAssignments()
        {
            TestHelpers.SeedCourses(_context);

            var instructor = new Instructor
            {
                FirstMidName = "Jane",
                LastName = "Smith",
                HireDate = DateTime.Parse("2020-01-01")
            };
            var selectedCourses = new[] { "1050", "4022" };

            var result = _controller.Create(instructor, selectedCourses);

            Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
            var saved = _context.Instructors.First(i => i.LastName == "Smith");
            var assignments = _context.CourseAssignments.Where(ca => ca.InstructorID == saved.ID).ToList();
            Assert.AreEqual(2, assignments.Count);
        }

        [TestMethod]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);

            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Edit_GET_ValidId_ReturnsViewResultWithInstructor()
        {
            TestHelpers.SeedFull(_context);

            var result = _controller.Edit(10) as ViewResult;

            Assert.IsNotNull(result);
            var instructor = result.Model as Instructor;
            Assert.IsNotNull(instructor);
            Assert.AreEqual(10, instructor.ID);
        }

        [TestMethod]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Delete_GET_NonexistentId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsInstanceOfType(result, typeof(NotFoundResult));
        }

        [TestMethod]
        public void Delete_GET_ValidId_ReturnsViewResult()
        {
            TestHelpers.SeedInstructors(_context);

            var result = _controller.Delete(10) as ViewResult;

            Assert.IsNotNull(result);
            var instructor = result.Model as Instructor;
            Assert.IsNotNull(instructor);
            Assert.AreEqual(10, instructor.ID);
        }

        [TestMethod]
        public void DeleteConfirmed_RemovesInstructor_AndRedirects()
        {
            TestHelpers.SeedFull(_context);
            Assert.IsTrue(_context.Instructors.Any(i => i.ID == 10));

            var result = _controller.DeleteConfirmed(10);

            Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
            Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
            Assert.IsFalse(_context.Instructors.Any(i => i.ID == 10));
        }

        [TestMethod]
        public void DeleteConfirmed_NullifiesDepartmentInstructorID()
        {
            TestHelpers.SeedFull(_context);

            // Assign instructor 10 as department admin
