namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public class InstructorsControllerTests
    {
        private SchoolContext _context = null!;
        private InstructorsController _controller = null!;

        [TestInitialize]
        public void Setup()
        {
            // Drain the static notification queue
            var drainer = new NotificationService();
            while (drainer.ReceiveNotification() != null) { }
            drainer.Dispose();

            _context = TestHelpers.CreateInMemoryContext();
            _controller = new InstructorsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            // Drain notifications left by tests
            var drainer = new NotificationService();
            while (drainer.ReceiveNotification() != null) { }
            drainer.Dispose();

            _controller.Dispose();
            _context.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsViewResult_WithInstructorIndexData()
        {
            TestHelpers.SeedFull(_context);

            var result = _controller.Index(null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.IsNotNull(model.Instructors);
        }

        [TestMethod]
        public void Index_WithInstructorId_SetsViewBagAndPopulatesCourses()
        {
            TestHelpers.SeedFull(_context);

            var result = _controller.Index(10, null) as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(10, (int)_controller.ViewBag.InstructorID);
            var model = result.Model as InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.IsNotNull(model.Courses);
            Assert.IsTrue(model.Courses.Any());
        }

        [TestMethod]
        public void Index_WithInstructorIdAndCourseId_SetsViewBagCourseIDAndPopulatesEnrollments()
        {
            TestHelpers.SeedFull(_context);

            var result = _controller.Index(10, 1050) as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(1050, (int)_controller.ViewBag.CourseID);
            var model = result.Model as InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.IsNotNull(model.Enrollments);
            Assert.IsTrue(model.Enrollments.Any());
        }

